import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const [passwordVisible, setPasswordVisible] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (username === '' || password === '') {
      setError(true);
    } else {
      setError(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <form onSubmit={handleSubmit} className="bg-white p-8 rounded-md shadow-md">
        <label className="block mb-2 text-sm font-bold text-gray-700">Username:</label>
        <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} className="block w-full px-3 py-2 mb-2 text-sm text-gray-700 bg-gray-50 border border-gray-300 rounded-md" placeholder="Username"/>
        <label className="block mb-2 text-sm font-bold text-gray-700">Password:</label>
        <div className="relative">
          <input type={passwordVisible ? "text" : "password" } value={password} onChange={(e) => setPassword(e.target.value)} className="block w-full px-3 py-2 mb-2 text-sm text-gray-700 bg-gray-50 border border-gray-300 rounded-md" placeholder="Password"/>
          <button type="button" onClick={() => setPasswordVisible(!passwordVisible)} className="absolute top-1/2 right-2 transform -translate-y-1/2 text-sm text-gray-700" aria-label="Toggle password visibility">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4" aria-hidden="true">
              <path d="M10 12a2 2 0 100-4 2 2 0 000 4z"/>
            </svg>
          </button>
        </div>
        <button type="submit" className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">Submit</button>
        {error && <p className="text-red-500 text-xs italic">Please fill out all fields</p>}
      </form>
    </div>
  );
};

export default App;
